 *
 * <p>A <code>null</code> CharSequence will return <code>true</code>.
 * A <code>null</code> invalid character array will return <code>true</code>.
 * An empty String ("") always returns true.</p>
 *
 * <pre>
 * StringUtils.containsNone(null, *)       = true
 * StringUtils.containsNone(*, null)       = true
 * StringUtils.containsNone("", *)         = true
 * StringUtils.containsNone("ab", "")      = true
 * StringUtils.containsNone("abab", "xyz") = true
 * StringUtils.containsNone("ab1", "xyz")  = true
 * StringUtils.containsNone("abz", "xyz")  = false
 * </pre>
 *
 * @param cs  the CharSequence to check, may be null
 * @param invalidChars  a String of invalid chars, may be null
 * @return true if it contains none of the invalid chars, or is null
 * @since 2.0
 */
public static boolean containsNone(CharSequence cs, String invalidChars) {
    if (cs == null || invalidChars == null) {
        return true;
    }
    // For supplementary characters handling, check if the invalidChars string appears as a substring
    int csLength = cs.length();
    int invalidLength = invalidChars.length();

    if (invalidLength == 0) {
        return true;
    }

    // If the input string is shorter than the invalid string, it cannot contain it
    if (csLength < invalidLength) {
        return true;
    }

    // Check if the entire invalidChars string appears as a substring in cs
    for (int i = 0; i <= csLength - invalidLength; i++) {
        boolean match = true;
        for (int j = 0; j < invalidLength; j++) {
            if (cs.charAt(i + j) != invalidChars.charAt(j)) {
                match = false;
                break;
            }
        }
        if (match) {
            return false; // Found the invalid sequence
        }
    }
    return true;
}

