 * A <code>null</code> invalid character array will return <code>true</code>.
 * An empty String (length()=0) always returns true.</p>
 *
 * <p>Note: When searching for supplementary Unicode characters (code points > 0xFFFF), 
 * this method treats them as sequences of chars and checks for complete matches.</p>
 *
 * <pre>
 * StringUtils.containsNone(null, *)       = true
 * StringUtils.containsNone(*, null)       = true
 * StringUtils.containsNone("", *)         = true
 * StringUtils.containsNone("ab", '')      = true
 * StringUtils.containsNone("abab", 'xyz') = true
 * StringUtils.containsNone("ab1", 'xyz')  = true
 * StringUtils.containsNone("abz", 'xyz')  = false
 * </pre>
 *
 * @param cs  the CharSequence to check, may be null
 * @param searchChars  an array of invalid chars, may be null
 * @return true if it contains none of the invalid chars, or is null
 * @since 2.0
 */
public static boolean containsNone(CharSequence cs, char[] searchChars) {
    if (cs == null || searchChars == null) {
        return true;
    }

    int csLen = cs.length();
    int searchLen = searchChars.length;

    // Check for complete sequence matches first for supplementary characters
    if (searchLen > 1) {
        for (int i = 0; i <= csLen - searchLen; i++) {
            boolean sequenceMatch = true;
            for (int j = 0; j < searchLen; j++) {
                if (cs.charAt(i + j) != searchChars[j]) {
                    sequenceMatch = false;
                    break;
                }
            }
            if (sequenceMatch) {
                return false; // Found the complete sequence
            }
        }
    }

    // Then check for individual character matches as fallback
    for (int i = 0; i < csLen; i++) {
        char ch = cs.charAt(i);
        for (int j = 0; j < searchLen; j++) {
            if (searchChars[j] == ch) {
                return false;
            }
        }
    }

    return true;
}

